def add_first_asm(block: int) -> str:
    lines = []
    for i in range(block):
        off = i * 8
        if i == 0:
            lines.append(f'"movq {off}(%[a]), %[t]\\n\\t"')
            lines.append(f'"addq {off}(%[b]), %[t]\\n\\t"')
        else:
            lines.append(f'"movq {off}(%[a]), %[t]\\n\\t"')
            lines.append(f'"adcq {off}(%[b]), %[t]\\n\\t"')
        lines.append(f'"movq %[t], {off}(%[r])\\n\\t"')
    lines.append('"sbbq %[cy], %[cy]\\n\\t"')
    lines.append('"negq %[cy]\\n\\t"')
    return "\n        ".join(lines)


