def rshift_small_asm(block: int) -> str:
    lines = []
    for i in range(0, block - 1):
        off = i * 8
        nxt = (i + 1) * 8
        lines.append(f'"movq {off}(%[a]), %[t0]\\n\\t"')
        lines.append(f'"movq {nxt}(%[a]), %[t1]\\n\\t"')
        lines.append(f'"shrdq %%cl, %[t1], %[t0]\\n\\t"')
        lines.append(f'"movq %[t0], {off}(%[r])\\n\\t"')
    off = (block - 1) * 8
    lines.append(f'"movq {off}(%[a]), %[t0]\\n\\t"')
    lines.append('"shrq %%cl, %[t0]\\n\\t"')
    lines.append(f'"movq %[t0], {off}(%[r])\\n\\t"')
    return "\n        ".join(lines)


def tier1_addmul(block: int) -> str:
    lines = [
        '        __asm__ __volatile__(',
        '            "movq %[scalar], %%rdx\\n\\t"',
        '            "xorl %%eax, %%eax\\n\\t"',
    ]
    prev_hi = None
    for i in range(block):
        off = i * 8
        hi = "%[co]" if i == block - 1 else ("%[t1]" if i % 2 == 0 else "%[t2]")
        acc = "%[ci]" if i == 0 else prev_hi
        lines.append(f'            "mulx {off}(%[a]), %[t0], {hi}\\n\\t"')
        lines.append(f'            "adox {acc}, %[t0]\\n\\t"')
        lines.append(f'            "adcx {off}(%[r]), %[t0]\\n\\t"')
        lines.append(f'            "movq %[t0], {off}(%[r])\\n\\t"')
        prev_hi = hi
    lines.extend([
        '            "movq $0, %[t0]\\n\\t"',
        '            "adox %[t0], %[co]\\n\\t"',
        '            "adcx %[t0], %[co]\\n\\t"',
        '            : [co] "=&r"(co), [t0] "=&r"(t0), [t1] "=&r"(t1), [t2] "=&r"(t2)',
        '            : [r] "r"(r), [a] "r"(a), [scalar] "r"(scalar), [ci] "r"(cy)',
        '            : "rax", "rdx", "cc", "memory");',
    ])
    return "\n".join(lines)


def tier2_addmul(block: int) -> str:
    lines = [
        '        __asm__ __volatile__(',
        '            "movq %[scalar], %%rdx\\n\\t"',
    ]
    hi = "%[co]" if block == 1 else "%[t1]"
    lines.extend([
        f'            "mulx 0(%[a]), %[t0], {hi}\\n\\t"',
        '            "addq 0(%[r]), %[t0]\\n\\t"',
        f'            "adcq $0, {hi}\\n\\t"',
        '            "addq %[ci], %[t0]\\n\\t"',
        f'            "adcq $0, {hi}\\n\\t"',
        '            "movq %[t0], 0(%[r])\\n\\t"',
    ])
    prev_hi = hi
    for i in range(1, block):
        off = i * 8
        hi = "%[co]" if i == block - 1 else ("%[t1]" if i % 2 == 0 else "%[t2]")
        lines.extend([
            f'            "mulx {off}(%[a]), %[t0], {hi}\\n\\t"',
            f'            "addq {prev_hi}, %[t0]\\n\\t"',
            f'            "adcq {off}(%[r]), %[t0]\\n\\t"',
            f'            "movq %[t0], {off}(%[r])\\n\\t"',
            f'            "adcq $0, {hi}\\n\\t"',
        ])
        prev_hi = hi
    lines.extend([
        '            : [co] "=&r"(co), [t0] "=&r"(t0), [t1] "=&r"(t1), [t2] "=&r"(t2)',
        '            : [r] "r"(r), [a] "r"(a), [scalar] "r"(scalar), [ci] "r"(cy)',
        '            : "rdx", "cc", "memory");',
        "        return co;",
    ])
    return "\n".join(lines)


