def tier2_submul(block: int) -> str:
    """BMI2-only ASM for submul1_block<B>: r[0..B-1] -= a[0..B-1] * scalar.
    Per-limb pattern: mulx + addq(prev_hi) + adcq(0) + subq(t0,r[i]) + adcq(0).
    """
    lines = [
        '        __asm__ __volatile__(',
        '            "movq %[scalar], %%rdx\\n\\t"',
    ]
    hi = "%[bo]" if block == 1 else "%[t1]"
    lines.extend([
        f'            "mulx 0(%[a]), %[t0], {hi}\\n\\t"',
        f'            "addq %[bi], %[t0]\\n\\t"',
        f'            "adcq $0, {hi}\\n\\t"',
        f'            "subq %[t0], 0(%[r])\\n\\t"',
        f'            "adcq $0, {hi}\\n\\t"',
    ])
    prev_hi = hi
    for i in range(1, block):
        off = i * 8
        hi = "%[bo]" if i == block - 1 else ("%[t1]" if i % 2 == 0 else "%[t2]")
        lines.extend([
            f'            "mulx {off}(%[a]), %[t0], {hi}\\n\\t"',
            f'            "addq {prev_hi}, %[t0]\\n\\t"',
            f'            "adcq $0, {hi}\\n\\t"',
            f'            "subq %[t0], {off}(%[r])\\n\\t"',
            f'            "adcq $0, {hi}\\n\\t"',
        ])
        prev_hi = hi
    lines.extend([
        '            : [bo] "=&r"(bo), [t0] "=&r"(t0), [t1] "=&r"(t1), [t2] "=&r"(t2)',
        '            : [r] "r"(r), [a] "r"(a), [scalar] "r"(scalar), [bi] "r"(bw)',
        '            : "rdx", "cc", "memory");',
        "        return bo;",
    ])
    return "\n".join(lines)


def tier1_submul(block: int) -> str:
    """BMI2+ADX ASM for submul1_block<B>.
    Uses GMP's complement trick: r -= a*s == r += ~(a*s) + 1.
    Two parallel carry chains: cf for the lo+~lo+r addition (via adcx),
    of for the hi accumulation (via adox).  The "borrow out" is the
    accumulated -hi value, which we negate at the end.
    """
    lines = [
        '        __asm__ __volatile__(',
        '            "movq %[scalar], %%rdx\\n\\t"',
        # Initialize: clear of (xor eax) and set cf=1 (stc, equivalent to "+1" for ~x+1 = -x)
        '            "xorl %%eax, %%eax\\n\\t"',
        '            "movq %[bi], %[bo]\\n\\t"',
        # Set cf for the initial +1: stc.  But we also need to subtract bi.
        # Easier path: bo accumulates -result_high; initialize bo = -bw_in (handled by neg).
        # Use neg to set CF = (bw_in != 0): if bw_in=0, neg sets cf=0; if bw_in=1, neg sets cf=1.
        '            "negq %[bo]\\n\\t"',
    ]
    # Loop body: per limb
    #   mulx a[i], t0, t1     ; t0:t1 = a[i]*scalar
    #   adox t1, bo           ; bo += t1 (using OF chain)
    #   not  t0               ; t0 = ~t0
    #   adcx r[i], t0         ; t0 += r[i] + CF (using CF chain)
    #   mov t0, r[i]
    # Need t1 != bo when block==1; use t2 for t1 in that case
    for i in range(block):
        off = i * 8
        hi_reg = "%[t1]" if i % 2 == 0 else "%[t2]"
        if block == 1:
            hi_reg = "%[t1]"
        lines.extend([
            f'            "mulx {off}(%[a]), %[t0], {hi_reg}\\n\\t"',
            f'            "adoxq {hi_reg}, %[bo]\\n\\t"',
            f'            "notq %[t0]\\n\\t"',
            f'            "adcxq {off}(%[r]), %[t0]\\n\\t"',
            f'            "movq %[t0], {off}(%[r])\\n\\t"',
        ])
    # Finalize: bo currently holds -result_high accumulated with both chains.
    # Need to fold the final cf and of into bo.
    #
    # After the loop:
    #   cf = 1 if no underflow on the last add, 0 if underflow
    #   of = 1 if of-chain on bo overflowed (rare)
    # bo holds the negated borrow with cf adjustment pending.
    # We want bw_out = -bo + (1 - cf) corrected for of.
    #
    # The simpler GMP idiom: at end,
    #   adox %[zero], %[bo]   ; absorb final of
    #   adc  $0, %[bo]        ; absorb final cf via the carry chain (becomes part of -bo)
    #   neg  %[bo]            ; bo = actual borrow_out
    lines.extend([
        '            "movq $0, %[t0]\\n\\t"',
        '            "adoxq %[t0], %[bo]\\n\\t"',
        '            "adcq  $0, %[bo]\\n\\t"',
        '            "negq  %[bo]\\n\\t"',
        '            : [bo] "+&r"(bo), [t0] "=&r"(t0), [t1] "=&r"(t1), [t2] "=&r"(t2)',
        '            : [scalar] "r"(scalar), [r] "r"(r), [a] "r"(a), [bi] "r"(bw)',
        '            : "rax", "rdx", "cc", "memory");',
    ])
    return "\n".join(lines)


def emit_submul1_block(block: int) -> str:
    return f"""
template<>
__attribute__((always_inline)) inline limb_t submul1_block<{block}>(limb_t* r, const limb_t* a, limb_t scalar, limb_t bw) {{
#if defined(ZFACTOR_HAS_BMI2)
    limb_t bo = 0, t0 = 0, t1 = 0, t2 = 0;
{tier2_submul(block)}
#else
    return generic_submul1_block<{block}>(r, a, scalar, bw);
#endif
}}
"""


def emit_sqr_small_2() -> str:
    return """
template<>
__attribute__((always_inline)) inline bool sqr_small_asm<2>(limb_t* r, const limb_t* a) {
#if defined(ZFACTOR_HAS_BMI2)
    __asm__ __volatile__(
        "movq 0(%[a]), %%rdx\\n\\t"
        "mulx 8(%[a]), %%r8, %%r9\\n\\t"
        "mulx 0(%[a]), %%rax, %%r10\\n\\t"
        "movq 8(%[a]), %%rdx\\n\\t"
        "mulx 8(%[a]), %%r11, %%rbx\\n\\t"
        "xorq %%rcx, %%rcx\\n\\t"
        "addq %%r8, %%r8\\n\\t"
        "adcq %%r9, %%r9\\n\\t"
        "adcq $0, %%rcx\\n\\t"
        "addq %%r8, %%r10\\n\\t"
        "adcq %%r11, %%r9\\n\\t"
        "adcq %%rcx, %%rbx\\n\\t"
        "movq %%rax, 0(%[r])\\n\\t"
        "movq %%r10, 8(%[r])\\n\\t"
        "movq %%r9, 16(%[r])\\n\\t"
        "movq %%rbx, 24(%[r])\\n\\t"
        :
        : [r] "r"(r), [a] "r"(a)
        : "rax", "rbx", "rcx", "rdx", "r8", "r9", "r10", "r11", "cc", "memory");
    return true;
#else
    (void)r;
    (void)a;
    return false;
#endif
}
"""


def emit_sqr_small_3() -> str:
    return """
template<>
__attribute__((always_inline)) inline bool sqr_small_asm<3>(limb_t* r, const limb_t* a) {
#if defined(ZFACTOR_HAS_BMI2) && defined(ZFACTOR_HAS_ADX)
    __asm__ __volatile__(
        "movq 0(%[a]), %%rdx\\n\\t"
        "mulx 8(%[a]), %%r10, %%r11\\n\\t"
        "mulx 16(%[a]), %%r8, %%r9\\n\\t"
        "addq %%r11, %%r8\\n\\t"
        "movq 8(%[a]), %%rdx\\n\\t"
        "mulx 16(%[a]), %%rax, %%r11\\n\\t"
        "adcq %%rax, %%r9\\n\\t"
        "adcq $0, %%r11\\n\\t"
        "xorq %%rcx, %%rcx\\n\\t"
        "movq 0(%[a]), %%rdx\\n\\t"
        "mulx 0(%[a]), %%rbx, %%rax\\n\\t"
        "movq %%rbx, 0(%[r])\\n\\t"
        "movq 8(%[a]), %%rdx\\n\\t"
        "mulx 8(%[a]), %%r14, %%r15\\n\\t"
        "movq 16(%[a]), %%rdx\\n\\t"
        "mulx 16(%[a]), %%rsi, %%rdx\\n\\t"
        "adcx %%r10, %%r10\\n\\t"
        "adcx %%r8, %%r8\\n\\t"
        "adcx %%r9, %%r9\\n\\t"
        "adcx %%r11, %%r11\\n\\t"
        "adox %%r10, %%rax\\n\\t"
        "adox %%r8, %%r14\\n\\t"
        "adox %%r9, %%r15\\n\\t"
        "adox %%r11, %%rsi\\n\\t"
        "adox %%rcx, %%rdx\\n\\t"
        "adcx %%rcx, %%rdx\\n\\t"
        "movq %%rax, 8(%[r])\\n\\t"
        "movq %%r14, 16(%[r])\\n\\t"
        "movq %%r15, 24(%[r])\\n\\t"
        "movq %%rsi, 32(%[r])\\n\\t"
        "movq %%rdx, 40(%[r])\\n\\t"
        :
        : [r] "r"(r), [a] "r"(a)
        : "rax", "rbx", "rcx", "rdx", "r8", "r9", "r10", "r11",
          "r14", "r15", "rsi", "cc", "memory");
    return true;
#else
    (void)r;
    (void)a;
    return false;
#endif
}
"""


def sqr_diag_asm(off: int) -> list[str]:
    return [
        f'"movq {off}(%[a]), %%rax\\n\\t"',
        f'"mulq {off}(%[a])\\n\\t"',
        '"addq %%rax, %%r8\\n\\t"',
        '"adcq %%rdx, %%r9\\n\\t"',
        '"adcq $0, %%r10\\n\\t"',
    ]


def sqr_cross_asm(offa: int, offb: int) -> list[str]:
    return [
        f'"movq {offa}(%[a]), %%rax\\n\\t"',
        f'"mulq {offb}(%[a])\\n\\t"',
        '"xorq %%rcx, %%rcx\\n\\t"',
        '"addq %%rax, %%rax\\n\\t"',
        '"adcq %%rdx, %%rdx\\n\\t"',
        '"adcq $0, %%rcx\\n\\t"',
        '"addq %%rax, %%r8\\n\\t"',
        '"adcq %%rdx, %%r9\\n\\t"',
        '"adcq %%rcx, %%r10\\n\\t"',
    ]


def sqr_store_asm(off: int) -> list[str]:
    return [
        f'"movq %%r8, {off}(%[r])\\n\\t"',
        '"movq %%r9, %%r8\\n\\t"',
        '"movq %%r10, %%r9\\n\\t"',
        '"xorq %%r10, %%r10\\n\\t"',
    ]


def emit_sqr_small_comba(block: int) -> str:
    lines = [
        '"xorq %%r8, %%r8\\n\\t"',
        '"xorq %%r9, %%r9\\n\\t"',
        '"xorq %%r10, %%r10\\n\\t"',
    ]
    for col in range(2 * block - 1):
        low = max(0, col - (block - 1))
        high = min((col - 1) // 2, block - 1)
        for i in range(low, high + 1):
            j = col - i
            if i < j < block:
                lines.extend(sqr_cross_asm(i * 8, j * 8))
        if col % 2 == 0:
            i = col // 2
            if i < block:
                lines.extend(sqr_diag_asm(i * 8))
        if col + 1 < 2 * block - 1:
            lines.extend(sqr_store_asm(col * 8))
    final_off = (2 * block - 2) * 8
    lines.extend([
        f'"movq %%r8, {final_off}(%[r])\\n\\t"',
        f'"movq %%r9, {final_off + 8}(%[r])\\n\\t"',
    ])
    body = "\n        ".join(lines)
    return f"""
template<>
__attribute__((always_inline)) inline bool sqr_small_asm<{block}>(limb_t* r, const limb_t* a) {{
#if defined(__x86_64__)
    __asm__ __volatile__(
        {body}
        :
        : [r] "r"(r), [a] "r"(a)
        : "rax", "rcx", "rdx", "r8", "r9", "r10", "cc", "memory");
    return true;
#else
    (void)r;
    (void)a;
    return false;
#endif
}}
"""


def emit_add_blocks() -> str:
    parts = []
    for block in range(1, 9):
        parts.append(
            f"""
template<>
__attribute__((always_inline)) inline uint8_t add_block_first<{block}>(limb_t* r, const limb_t* a, const limb_t* b) {{
    limb_t carry, t;
    __asm__ __volatile__(
        {add_first_asm(block)}
        : [cy] "=r"(carry), [t] "=&r"(t)
        : [r] "r"(r), [a] "r"(a), [b] "r"(b)
        : "cc", "memory");
    return static_cast<uint8_t>(carry);
}}

template<>
__attribute__((always_inline)) inline uint8_t add_block<{block}>(limb_t* r, const limb_t* a, const limb_t* b, uint8_t cy) {{
    limb_t carry = cy;
    limb_t t;
    __asm__ __volatile__(
        {add_carry_asm(block)}
        : [cy] "+r"(carry), [t] "=&r"(t)
        : [r] "r"(r), [a] "r"(a), [b] "r"(b)
        : "cc", "memory");
    return static_cast<uint8_t>(carry);
}}
"""
        )
    return "\n".join(parts)


