def render() -> str:
    parts = [
        HEADER,
        emit_add_blocks(),
        emit_sub_blocks(),
        emit_add1_blocks(),
        emit_sub1_blocks(),
        emit_shift_blocks(),
    ]
    for block in range(1, 9):
        parts.append(emit_addmul1_block(block))
    for block in range(1, 9):
        parts.append(emit_submul1_block(block))
    parts.append(emit_sqr_small_2())
    parts.append(emit_sqr_small_3())
    parts.append(emit_sqr_small_comba(4))
    parts.append(FOOTER)
    return "".join(parts)


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("--output", required=True)
    parser.add_argument("--max-n", type=int, help="Deprecated no-op; generated dispatch is unbounded.")
    parser.add_argument("--arch", required=True, choices=["x86_64"])
    args = parser.parse_args()

    output = Path(args.output)
    output.parent.mkdir(parents=True, exist_ok=True)
    output.write_text(render(), encoding="utf-8", newline="\n")


if __name__ == "__main__":
    main()
